<?php require "vendor/autoload.php"; $app = require_once "bootstrap/app.php"; $kernel = $app->make(Illuminate\Contracts\Console\Kernel::class); $kernel->bootstrap(); try { $curso = App\Models\Curso::find(18); $user = App\Models\User::find(91);  if(!$curso || !$user) { die("No curso o user"); } $resumen = $curso->getResumenCalificacionesEstudiante($user->id); $plantilla = $curso->plantillaCertificado; if ($plantilla) { $certificadoEmitido = \App\Models\CertificadoEmitido::obtenerOCrear($curso->id, $user->id, $resumen["nota_final"] ?? 0, $plantilla->id); print_r($certificadoEmitido->toArray()); echo "\nProbando view:\n"; $html = view("academico.curso.certificado", ["curso" => $curso,"user" => $user,"resumen" => $resumen,"plantilla" => $plantilla,"notaFinal" => number_format($resumen["nota_final"] ?? 0, 1),"certificadoEmitido" => $certificadoEmitido,])->render(); echo "View OK. length: " . strlen($html); } else { echo "No plantilla"; } } catch (\Throwable $e) { echo "ERROR: " . $e->getFile() . ":" . $e->getLine() . " - " . $e->getMessage(); }
